1876 /// Compute the cost for the intrinsic \p ID with \p Operands, produced by \p R.
1877 static InstructionCost getCostForIntrinsics(Intrinsic::ID ID,
1878                                             ArrayRef<const VPValue *> Operands,
1879                                             const VPRecipeWithIRFlags &R,
1880                                             ElementCount VF,
1881                                             VPCostContext &Ctx) {
1882   // Some backends analyze intrinsic arguments to determine cost. Use the
1883   // underlying value for the operand if it has one. Otherwise try to use the
1884   // operand of the underlying call instruction, if there is one. Otherwise
1885   // clear Arguments.
1886   // TODO: Rework TTI interface to be independent of concrete IR values.
1887   SmallVector<const Value *> Arguments;
1888   for (const auto &[Idx, Op] : enumerate(Operands)) {
1889     auto *V = Op->getUnderlyingValue();
1890     if (!V) {
1891       if (auto *UI = dyn_cast_or_null<CallBase>(R.getUnderlyingValue())) {
1892         Arguments.push_back(UI->getArgOperand(Idx));
1893         continue;
1894       }
1895       Arguments.clear();
1896       break;
1897     }
1898     Arguments.push_back(V);
1899   }
1900 
1901   Type *ScalarRetTy = Ctx.Types.inferScalarType(&R);
1902   Type *RetTy = VF.isVector() ? toVectorizedTy(ScalarRetTy, VF) : ScalarRetTy;
1903   SmallVector<Type *> ParamTys;
1904   for (const VPValue *Op : Operands) {
1905     ParamTys.push_back(VF.isVector()
1906                            ? toVectorTy(Ctx.Types.inferScalarType(Op), VF)
1907                            : Ctx.Types.inferScalarType(Op));
1908   }
1909 
1910   // TODO: Rework TTI interface to avoid reliance on underlying IntrinsicInst.
1911   FastMathFlags FMF =
1912       R.hasFastMathFlags() ? R.getFastMathFlags() : FastMathFlags();
1913   IntrinsicCostAttributes CostAttrs(
1914       ID, RetTy, Arguments, ParamTys, FMF,
1915       dyn_cast_or_null<IntrinsicInst>(R.getUnderlyingValue()),
1916       InstructionCost::getInvalid(), &Ctx.TLI);
1917   return Ctx.TTI.getIntrinsicInstrCost(CostAttrs, Ctx.CostKind);
1918 }
1919 
1920 InstructionCost VPWidenIntrinsicRecipe::computeCost(ElementCount VF,
1921                                                     VPCostContext &Ctx) const {
1922   SmallVector<const VPValue *> ArgOps(operands());
1923   return getCostForIntrinsics(VectorIntrinsicID, ArgOps, *this, VF, Ctx);
