1961 void VPHistogramRecipe::execute(VPTransformState &State) {
1962   IRBuilderBase &Builder = State.Builder;
1963 
1964   Value *Address = State.get(getOperand(0));
1965   Value *IncAmt = State.get(getOperand(1), /*IsScalar=*/true);
1966   VectorType *VTy = cast<VectorType>(Address->getType());
1967 
1968   // The histogram intrinsic requires a mask even if the recipe doesn't;
1969   // if the mask operand was omitted then all lanes should be executed and
1970   // we just need to synthesize an all-true mask.
1971   Value *Mask = nullptr;
1972   if (VPValue *VPMask = getMask())
1973     Mask = State.get(VPMask);
1974   else
1975     Mask =
1976         Builder.CreateVectorSplat(VTy->getElementCount(), Builder.getInt1(1));
1977 
1978   // If this is a subtract, we want to invert the increment amount. We may
1979   // add a separate intrinsic in future, but for now we'll try this.
1980   if (Opcode == Instruction::Sub)
1981     IncAmt = Builder.CreateNeg(IncAmt);
1982   else
1983     assert(Opcode == Instruction::Add && "only add or sub supported for now");
1984 
1985   State.Builder.CreateIntrinsic(Intrinsic::experimental_vector_histogram_add,
1986                                 {VTy, IncAmt->getType()},
1987                                 {Address, IncAmt, Mask});
1988 }
