1990 InstructionCost VPHistogramRecipe::computeCost(ElementCount VF,
1991                                                VPCostContext &Ctx) const {
1992   // FIXME: Take the gather and scatter into account as well. For now we're
1993   //        generating the same cost as the fallback path, but we'll likely
1994   //        need to create a new TTI method for determining the cost, including
1995   //        whether we can use base + vec-of-smaller-indices or just
1996   //        vec-of-pointers.
1997   assert(VF.isVector() && "Invalid VF for histogram cost");
1998   Type *AddressTy = Ctx.Types.inferScalarType(getOperand(0));
1999   VPValue *IncAmt = getOperand(1);
2000   Type *IncTy = Ctx.Types.inferScalarType(IncAmt);
2001   VectorType *VTy = VectorType::get(IncTy, VF);
2002 
2003   // Assume that a non-constant update value (or a constant != 1) requires
2004   // a multiply, and add that into the cost.
2005   InstructionCost MulCost =
2006       Ctx.TTI.getArithmeticInstrCost(Instruction::Mul, VTy, Ctx.CostKind);
2007   if (auto *CI = dyn_cast<VPConstantInt>(IncAmt))
2008     if (CI->isOne())
2009       MulCost = TTI::TCC_Free;
2010 
2011   // Find the cost of the histogram operation itself.
2012   Type *PtrTy = VectorType::get(AddressTy, VF);
2013   Type *MaskTy = VectorType::get(Type::getInt1Ty(Ctx.LLVMCtx), VF);
2014   IntrinsicCostAttributes ICA(Intrinsic::experimental_vector_histogram_add,
2015                               Type::getVoidTy(Ctx.LLVMCtx),
2016                               {PtrTy, IncTy, MaskTy});
2017 
2018   // Add the costs together with the add/sub operation.
2019   return Ctx.TTI.getIntrinsicInstrCost(ICA, Ctx.CostKind) + MulCost +
2020          Ctx.TTI.getArithmeticInstrCost(Opcode, VTy, Ctx.CostKind);
2021 }
