2357 InstructionCost VPWidenRecipe::computeCost(ElementCount VF,
2358                                            VPCostContext &Ctx) const {
2359   switch (Opcode) {
2360   case Instruction::UDiv:
2361   case Instruction::SDiv:
2362   case Instruction::SRem:
2363   case Instruction::URem:
2364     // If the div/rem operation isn't safe to speculate and requires
2365     // predication, then the only way we can even create a vplan is to insert
2366     // a select on the second input operand to ensure we use the value of 1
2367     // for the inactive lanes. The select will be costed separately.
2368   case Instruction::FNeg:
2369   case Instruction::Add:
2370   case Instruction::FAdd:
2371   case Instruction::Sub:
2372   case Instruction::FSub:
2373   case Instruction::Mul:
2374   case Instruction::FMul:
2375   case Instruction::FDiv:
2376   case Instruction::FRem:
2377   case Instruction::Shl:
2378   case Instruction::LShr:
2379   case Instruction::AShr:
2380   case Instruction::And:
2381   case Instruction::Or:
2382   case Instruction::Xor:
2383   case Instruction::Freeze:
2384   case Instruction::ExtractValue:
2385   case Instruction::ICmp:
